const sig = $request.headers['x-asset-persona-signature'];
const secret = $env.N8N_HMAC_SECRET;
const raw = JSON.stringify($json);
const expected = require('crypto').createHmac('sha256', secret).update(raw).digest('hex');
if (sig !== expected) throw new Error('hmac_mismatch');
return [{ json: $json }];

// Build the email body from the payload.
const p = $json;
const nameLine = p.user?.display_name ? `Nice work, ${p.user.display_name}.` : 'Nice work.';
const nextLine = p.next_slug
  ? `Next up: https://www.assetpersona.com/community/learn/${p.next_slug}`
  : `Pick your next drill: https://www.assetpersona.com/community/learn`;
const body = `${nameLine}\n\nYou just finished "${p.module.title}" — +${p.xp_earned} XP, streak bumped.\n\n${nextLine}\n\n— Frank`;
return [{ json: { ...p, body, subject: `+${p.xp_earned} XP — "${p.module.title}" complete` } }];
